// src/components/ChatBot.jsx
import React, { useState } from "react";

export default function ChatBot() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");

  const sendMessage = async () => {
    if (!input.trim()) return;

    const userMsg = { role: "user", content: input };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");

    try {
      const res = await fetch("http://localhost:3000/chat", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ message: input }),
      });

      const data = await res.json();
      const botMsg = { role: "bot", content: data.response };

      setMessages((prev) => [...prev, botMsg]);
    } catch (err) {
      setMessages((prev) => [
        ...prev,
        { role: "bot", content: "Error: no se pudo conectar con el servidor." },
      ]);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter") sendMessage();
  };

  return (
    <div className="fixed bottom-4 right-4 w-80 bg-white border shadow-lg rounded-lg flex flex-col max-h-[500px] overflow-hidden z-50">
      <div className="bg-indigo-600 text-white p-3 font-semibold">
        🤖 Preguntá sobre mi experiencia
      </div>
      <div className="flex-1 overflow-y-auto p-3 space-y-2 text-sm">
        {messages.map((msg, i) => (
          <div
            key={i}
            className={`${
              msg.role === "user" ? "text-right text-blue-700" : "text-left text-gray-800"
            }`}
          >
            <p className="bg-gray-100 inline-block px-3 py-1 rounded">
              {msg.content}
            </p>
          </div>
        ))}
      </div>
      <div className="p-2 border-t flex">
        <input
          className="flex-1 text-sm px-2 py-1 border rounded mr-2"
          type="text"
          placeholder="Escribí tu pregunta..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
        />
        <button
          onClick={sendMessage}
          className="bg-indigo-600 text-white px-3 py-1 rounded text-sm"
        >
          Enviar
        </button>
      </div>
    </div>
  );
}
